import React, { Component } from 'react';
import './BtnHeader.css';
import NewTabBtn from "./NewTabBtn.js"

class BtnHeader extends Component {
    render() {
        const {
            title,
            description
        } = this.props;

        return (
            <div>
                <NewTabBtn
                    title="Google"
                    link="https://google.com"
                />
                <NewTabBtn
                    title="Apple"
                    link="https://apple.com"
                />
                <NewTabBtn
                    title="Facebook"
                    link="https://meta.com"
                />
            </div>
        );
    }
}

export default BtnHeader;
